"use strict";(self.webpackChunkkmp_iap_docs=self.webpackChunkkmp_iap_docs||[]).push([[5894],{6042:e=>{e.exports=JSON.parse('{"blogPosts":[{"id":"initial-release","metadata":{"permalink":"/blog/initial-release","editUrl":"https://github.com/hyochan/kmp-iap/tree/main/docs/blog/2025-08-10-initial-release.md","source":"@site/blog/2025-08-10-initial-release.md","title":"Initial Release - StoreKit 2 and Google Play Billing Library Support","description":"kmp-iap Initial Release \ud83c\udf89","date":"2025-08-10T00:00:00.000Z","formattedDate":"August 10, 2025","tags":[{"label":"release","permalink":"/blog/tags/release"},{"label":"StoreKit2","permalink":"/blog/tags/store-kit-2"},{"label":"android","permalink":"/blog/tags/android"},{"label":"billing","permalink":"/blog/tags/billing"}],"readingTime":1.11,"hasTruncateMarker":false,"authors":[{"name":"Hyo","title":"Maintainer of kmp-iap","url":"https://github.com/hyochan","imageURL":"https://github.com/hyochan.png","key":"hyochan"}],"frontMatter":{"slug":"initial-release","title":"Initial Release - StoreKit 2 and Google Play Billing Library Support","authors":["hyochan"],"tags":["release","StoreKit2","android","billing"]},"unlisted":false},"content":"## kmp-iap Initial Release \ud83c\udf89\\n\\nWe\'re excited to announce the first release of **kmp-iap**, a unified in-app purchase library for Kotlin Multiplatform!\\n\\n## Key Features\\n\\n### \ud83c\udf4e iOS - Full StoreKit 2 Support\\n\\n- Complete support for Apple\'s latest StoreKit 2 framework\\n- Enhanced purchase verification and transaction management\\n- Improved subscription status tracking\\n- Leverages modern Swift async/await patterns\\n\\n### \ud83e\udd16 Android - Google Play Billing Library 7.1.1 Support\\n\\nSupporting Google Play Billing Library 7.1.1 with comprehensive features:\\n\\n- **Product Details API**: Modern API for querying product information\\n- **Subscription offers**: Support for multiple subscription offers and pricing phases\\n- **Pending purchases**: Full support for pending transactions\\n- **Error handling**: Detailed error codes and debugging information\\n- **Purchase verification**: Secure purchase token verification\\n\\n### \ud83c\udfaf Unified API\\n\\n- Same API for in-app purchases on both iOS and Android\\n- Reactive programming with Kotlin Coroutines and Flow\\n- Type-safe Kotlin native implementation\\n\\n## Getting Started\\n\\n```kotlin\\n// Initialize\\nKmpIAP.initConnection()\\n\\n// Load products\\nval products = KmpIAP.requestProducts(\\n    ProductRequest(\\n        skus = listOf(\\"product_id\\"),\\n        type = ProductType.INAPP\\n    )\\n)\\n\\n// Request purchase\\nKmpIAP.requestPurchase(\\n    UnifiedPurchaseRequest(\\n        sku = \\"product_id\\",\\n        quantity = 1\\n    )\\n)\\n\\n// Observe purchase state\\nKmpIAP.purchaseUpdatedListener.collect { purchase ->\\n    // Handle purchase\\n}\\n```\\n\\n## Next Steps\\n\\nWe\'ll continue to improve the library and add new features. Your feedback and contributions are welcome!\\n\\nGitHub: [https://github.com/hyochan/kmp-iap](https://github.com/hyochan/kmp-iap)"}]}')}}]);